/**
 * CRUD Audit Gap Tests — NavMelb Backend
 *
 * Generated by crud-sweep audit. Each test is tagged with the edge case ID
 * from the standard audit matrix so failures can be traced back to the audit.
 *
 * Since this project has no database, "CRUD" maps to:
 *   READ  → query/search endpoints + service lookups
 *   Cross → input validation, external API failure, boundary values
 */

import { describe, it, expect, beforeAll, vi, afterEach } from "vitest";
import request from "supertest";
import type { Express } from "express";
import { createTestApp } from "../helpers/create-app";

// ---------------------------------------------------------------------------
// Shared mocks
// ---------------------------------------------------------------------------

vi.mock("../../services/geocoding.service", () => ({
  geocodeAddress: vi.fn(async (query: string) => {
    if (query.toLowerCase().includes("federation square")) {
      return { lat: -37.818, lng: 144.969 };
    }
    return null;
  }),
}));

vi.mock("../../services/ptv-api.service", () => ({
  ptvSearchStops: vi.fn(async () => [
    {
      displayName: "Flinders Street Station",
      position: { lat: -37.8183, lng: 144.9671 },
      routeType: [0],
    },
  ]),
  ptvGetDepartures: vi.fn(async () => []),
  ptvFindStopByName: vi.fn(async () => null),
  ptvFindRouteBetweenStops: vi.fn(async () => null),
}));

vi.mock("axios", () => ({
  default: {
    get: vi.fn(async (url: string) => {
      if (url.includes("router.project-osrm.org") || url.includes("localhost:5000")) {
        return {
          data: {
            code: "Ok",
            routes: [
              {
                geometry: { coordinates: [[144.9631, -37.8136], [144.9671, -37.8183]] },
                distance: 1200,
                duration: 180,
              },
            ],
          },
        };
      }
      // Nominatim
      if (url.includes("nominatim.openstreetmap.org")) {
        return { data: [] };
      }
      throw new Error(`Unexpected URL: ${url}`);
    }),
  },
}));

// ---------------------------------------------------------------------------

let app: Express;
beforeAll(async () => {
  app = await createTestApp();
});

afterEach(() => {
  vi.restoreAllMocks();
});

// ===========================================================================
// GET /api/map/destination/lookup — additional gap coverage
// ===========================================================================

describe("GET /api/map/destination/lookup — gap coverage", () => {
  // CRUD audit: R5 — search with special characters
  it("R5: handles percent-encoded special characters in query without crashing", async () => {
    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "Flinders%20Street%20%26%20More" });

    // Should not 500 — returns 200 or 404, never a server error
    expect(res.status).not.toBe(500);
    expect(res.body).toHaveProperty("success");
  });

  // CRUD audit: R5 — SQL-injection-like string in query (sanitation check)
  it("R5: handles SQL-injection-like string gracefully", async () => {
    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "'; DROP TABLE stops; --" });

    expect(res.status).not.toBe(500);
    expect(res.body.success).toBe(false); // 404 since place not found
  });

  // CRUD audit: C6/R4 — empty string query
  it("R4/C6: empty string query returns 400", async () => {
    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "" });

    // empty string is falsy → the route guard should fire
    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: X1 — Unicode station name round-trip
  it("X1: Unicode query string does not crash the lookup", async () => {
    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "日本語テスト" });

    expect(res.status).not.toBe(500);
  });

  // CRUD audit: X8 — geocoding service down (returns null)
  it("X8: returns 404 (not 500) when geocoding service returns null", async () => {
    const { geocodeAddress } = await import("../../services/geocoding.service");
    vi.mocked(geocodeAddress).mockResolvedValueOnce(null);

    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "Nonexistent Place XYZ999" });

    expect(res.status).toBe(404);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: X8 — geocoding service throws (unexpected failure)
  it("X8: returns 500 when geocoding service throws unexpectedly", async () => {
    const { geocodeAddress } = await import("../../services/geocoding.service");
    vi.mocked(geocodeAddress).mockRejectedValueOnce(new Error("Network failure"));

    const res = await request(app)
      .get("/api/map/destination/lookup")
      .query({ query: "Federation Square" });

    expect(res.status).toBe(500);
    expect(res.body.success).toBe(false);
    expect(res.body.error).toMatch(/failed to lookup/i);
  });
});

// ===========================================================================
// GET /api/map/stations/search — additional gap coverage
// ===========================================================================

describe("GET /api/map/stations/search — gap coverage", () => {
  // CRUD audit: R5 — special characters in query
  it("R5: handles ampersand and special chars in query", async () => {
    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "Flinders & Swanston" });

    expect(res.status).not.toBe(500);
    expect(res.body).toHaveProperty("success");
  });

  // CRUD audit: C6/R4 — empty string query
  it("R4: empty string query returns 400", async () => {
    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "" });

    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: C6 — limit of zero
  // Fixed: `limit !== undefined ? Number(limit) : 50` now respects 0.
  it("C6: limit=0 returns empty array (slice(0,0) = nothing)", async () => {
    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "flinders", limit: "0" });

    expect(res.status).toBe(200);
    expect(res.body.data).toEqual([]);
  });

  // CRUD audit: C3 — non-numeric limit is ignored and defaults to 50
  it("C3: non-numeric limit falls back to default (50)", async () => {
    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "flinders", limit: "banana" });

    expect(res.status).toBe(200);
    expect(res.body.data.length).toBeLessThanOrEqual(50);
  });

  // CRUD audit: R2 — PTV returns empty list for unknown query
  it("R2: returns empty data array (not 404) when PTV finds no stops", async () => {
    const { ptvSearchStops } = await import("../../services/ptv-api.service");
    vi.mocked(ptvSearchStops).mockResolvedValueOnce([]);

    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "zzznomatch" });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
    expect(res.body.data).toEqual([]);
  });

  // CRUD audit: X8 — PTV API throws
  it("X8: returns 500 when PTV API throws", async () => {
    const { ptvSearchStops } = await import("../../services/ptv-api.service");
    vi.mocked(ptvSearchStops).mockRejectedValueOnce(new Error("PTV down"));

    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "flinders" });

    expect(res.status).toBe(500);
    expect(res.body.success).toBe(false);
    expect(res.body.error).toMatch(/failed to search stations/i);
  });

  // CRUD audit: C3 — unknown transportType is ignored (returns all)
  it("C3: unknown transportType value returns all results (not 400)", async () => {
    const res = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "flinders", transportType: "hovercraft" });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
    // "hovercraft" is not train/tram/bus, so the filter falls through to `return true`
    expect(res.body.data.length).toBeGreaterThan(0);
  });

  // CRUD audit: R9 — case sensitivity (query is normalized by PTV mock)
  it("R9: uppercase query returns same number of results as lowercase", async () => {
    const lower = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "flinders" });
    const upper = await request(app)
      .get("/api/map/stations/search")
      .query({ query: "FLINDERS" });

    expect(lower.status).toBe(200);
    expect(upper.status).toBe(200);
    // Both pass the query to ptvSearchStops which is mocked identically
    expect(upper.body.data.length).toBe(lower.body.data.length);
  });
});

// ===========================================================================
// POST /api/map/distance — additional gap coverage
// ===========================================================================

describe("POST /api/map/distance — gap coverage", () => {
  // CRUD audit: C3 — string passed where number expected
  it("C3: string lat/lng values are coerced gracefully", async () => {
    const res = await request(app)
      .post("/api/map/distance")
      .send({ from: { lat: "not-a-number", lng: 144.9631 }, to: { lat: -37.8676, lng: 144.9811 } });

    // NaN coordinates — the handler should 400 or return NaN-free distance
    // The current guard only checks `!from.lat` — "not-a-number" is truthy so it passes.
    // This documents existing behaviour (returns 200 with NaN distance) or 400 if hardened.
    expect([200, 400]).toContain(res.status);
  });

  // CRUD audit: C6 — near-antipodal coordinates (non-zero longitudes to avoid falsy-zero bug)
  // Note: using lng=1 instead of 0 because `!from.lng` fires for lng=0 (falsy-zero bug).
  it("C6: near-antipodal coordinates return large finite distance", async () => {
    const res = await request(app)
      .post("/api/map/distance")
      .send({ from: { lat: 89, lng: 1 }, to: { lat: -89, lng: 179 } });

    expect(res.status).toBe(200);
    expect(Number.isFinite(res.body.data.distance)).toBe(true);
    expect(res.body.data.distance).toBeGreaterThan(15_000_000); // ~half earth circumference
  });

  // CRUD audit: C6 — null island: lat=0 and lng=0 for `from`
  // Fixed: guard now uses `== null` instead of `!from.lat`, so 0 is accepted.
  it("C6: null island (lat=0, lng=0) is a valid coordinate and returns 200", async () => {
    const res = await request(app)
      .post("/api/map/distance")
      .send({ from: { lat: 0, lng: 0 }, to: { lat: 1, lng: 1 } });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
    expect(res.body.data.distance).toBeGreaterThan(0);
  });

  // CRUD audit: C2 — body with no content at all
  it("C2: completely empty body returns 400", async () => {
    const res = await request(app)
      .post("/api/map/distance")
      .send({});

    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: C5 — lat present but null
  it("C5: null lat value returns 400", async () => {
    const res = await request(app)
      .post("/api/map/distance")
      .send({ from: { lat: null, lng: 144.9631 }, to: { lat: -37.8676, lng: 144.9811 } });

    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });
});

