describe("GET /api/map/streets/search — gap coverage", () => {
  // CRUD audit: R5 — wildcard-like characters that could break string matching
  it("R5: percent character in query does not crash search", async () => {
    const res = await request(app)
      .get("/api/map/streets/search")
      .query({ query: "Flinders %" });

    expect(res.status).not.toBe(500);
  });

  // CRUD audit: C6 — very long query string (boundary)
  it("C6: very long query string (256 chars) is handled without error", async () => {
    const longQuery = "a".repeat(256);
    const res = await request(app)
      .get("/api/map/streets/search")
      .query({ query: longQuery });

    expect(res.status).not.toBe(500);
    expect(res.body.data).toEqual([]);
  });

  // CRUD audit: C3 — negative limit falls back to default
  it("C3: negative limit is treated as default (returns up to 20)", async () => {
    const res = await request(app)
      .get("/api/map/streets/search")
      .query({ query: "Flinders", limit: "-5" });

    // Number(-5) = -5, slice(0, -5) on an array truncates from the end — documents this behaviour
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body.data)).toBe(true);
  });

  // CRUD audit: X1 — Unicode query round-trip
  it("X1: Unicode query in streets search does not crash", async () => {
    const res = await request(app)
      .get("/api/map/streets/search")
      .query({ query: "日本語" });

    expect(res.status).toBe(200);
    expect(res.body.data).toEqual([]);
  });
});

