describe("GET /api/map/streets/nearby — gap coverage", () => {
  // CRUD audit: C3 — non-numeric lat/lng
  it("C3: non-numeric lat returns 400 or NaN-safe response", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ lat: "notanumber", lng: "144.9671" });

    // Documents: current guard only checks presence, not numeric validity
    expect([200, 400]).toContain(res.status);
  });

  // CRUD audit: C6 — zero radius
  // Fixed: `radius !== undefined ? Number(radius) : 200` now respects 0.
  // Note: radius=0 means "distance <= 0" — only exact-center matches pass.
  it("C6: radius=0 only returns streets at exactly distance 0 (not the 200m default)", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ lat: "-37.82", lng: "144.97", radius: "0" });

    expect(res.status).toBe(200);
    // With an offset point, no street center is at distance exactly 0
    expect(res.body.data).toEqual([]);
  });

  // CRUD audit: C6 — extremely large radius (should not crash)
  it("C6: extremely large radius (10000m) does not crash", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ lat: "-37.8183", lng: "144.9671", radius: "10000" });

    expect(res.status).toBe(200);
    expect(Array.isArray(res.body.data)).toBe(true);
  });

  // CRUD audit: C2 — both lat and lng missing
  it("C2: missing both lat and lng returns 400", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ radius: "200" });

    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: C6 — out-of-range coordinates (latitude > 90)
  it("C6: out-of-range latitude does not crash server", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ lat: "999", lng: "144.9671", radius: "200" });

    expect(res.status).not.toBe(500);
  });

  // CRUD audit: C3 — limit=0 in nearby streets
  // Fixed: `limit !== undefined ? Number(limit) : 20` now respects 0.
  it("C3: limit=0 returns empty results (slice(0,0) = nothing)", async () => {
    const res = await request(app)
      .get("/api/map/streets/nearby")
      .query({ lat: "-37.8183", lng: "144.9671", radius: "500", limit: "0" });

    expect(res.status).toBe(200);
    expect(res.body.data).toEqual([]);
  });
});

// ===========================================================================
// POST /api/map/route/calculate — additional gap coverage
// ===========================================================================

describe("POST /api/map/route/calculate — gap coverage", () => {
  const origin = { lat: -37.8136, lng: 144.9631 };
  const destination = { lat: -37.8235, lng: 144.9898 };

  // CRUD audit: C3 — missing strategy field entirely
  it("C2: missing strategy field returns 400", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination });

    expect(res.status).toBe(400);
    expect(res.body.success).toBe(false);
  });

  // CRUD audit: C5 — origin lat=0 is a valid coordinate (equator)
  // Fixed: guard now uses `== null` instead of `!origin.lat`.
  it("C5: origin.lat = 0 is accepted as valid coordinate", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin: { lat: 0, lng: 144.9631 }, destination, strategy: "car" });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  // CRUD audit: X6 — departureTime in HH:MM format is normalised to HH:MM:SS
  it("X6: HH:MM departureTime is accepted and normalised to HH:MM:SS", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination, strategy: "car", departureTime: "08:30" });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  // CRUD audit: X6 — departureTime at midnight edge
  it("X6: departureTime=00:00:00 is accepted", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination, strategy: "car", departureTime: "00:00:00" });

    expect(res.status).toBe(200);
  });

  // CRUD audit: X8 — OSRM down, verify fallback geometry is present
  it("X8: OSRM failure falls back to straight-line geometry (2 points)", async () => {
    const axios = await import("axios");
    vi.mocked(axios.default.get).mockRejectedValueOnce(new Error("OSRM unavailable"));

    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination, strategy: "car" });

    expect(res.status).toBe(200);
    const seg = res.body.data.segments[0];
    expect(seg.type).toBe("car");
    expect(seg.coordinates).toHaveLength(2); // straight-line fallback
  });

  // CRUD audit: D4 / R2 — PTV route not found for station pair → failed segment, 207
  it("R2/D4: PTV route not found returns 207 with failed segment", async () => {
    const { ptvFindRouteBetweenStops } = await import("../../services/ptv-api.service");
    vi.mocked(ptvFindRouteBetweenStops).mockResolvedValueOnce(null);

    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({
        origin,
        destination,
        strategy: "ptv",
        waypoints: [
          { position: { lat: -37.8183, lng: 144.9671 }, type: "station", name: "Flinders Street" },
          { position: { lat: -37.8235, lng: 144.9898 }, type: "station", name: "Richmond" },
        ],
      });

    // 207 Multi-Status when at least one leg fails
    expect(res.status).toBe(207);
    const failedSegs = res.body.data.segments.filter((s: { type: string }) => s.type === "failed");
    expect(failedSegs.length).toBeGreaterThan(0);
  });

  // CRUD audit: C3 — waypoints with no `type` field (place waypoints only, no stations)
  it("C3: ptv strategy with only place-type waypoints returns 400", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({
        origin,
        destination,
        strategy: "ptv",
        waypoints: [
          { position: { lat: -37.8183, lng: 144.9671 }, type: "place", name: "Some Place" },
        ],
      });

    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/at least one station/i);
  });

  // CRUD audit: X2 — response always includes estimatedArrival ISO timestamp
  it("X2: response always includes a valid ISO 8601 estimatedArrival timestamp", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination, strategy: "car" });

    expect(res.status).toBe(200);
    const arrival = res.body.data.estimatedArrival;
    expect(arrival).toBeDefined();
    expect(new Date(arrival).getTime()).not.toBeNaN();
  });

  // CRUD audit: X2 — top-level response timestamp is always present
  it("X2: response always includes a valid top-level timestamp", async () => {
    const res = await request(app)
      .post("/api/map/route/calculate")
      .send({ origin, destination, strategy: "car" });

    expect(res.status).toBe(200);
    expect(new Date(res.body.timestamp).getTime()).not.toBeNaN();
  });
});

